@Component
class SamlAuthenticationFilter extends AbstractAuthenticationProcessingFilter {

    SamlAuthenticationFilter(SamlAuthenticationProvider provider) {
        super("/saml/acs");
        setAuthenticationManager(authentication -> provider.authenticate(authentication));
        setAuthenticationSuccessHandler(successHandler());
    }

    private AuthenticationSuccessHandler successHandler() {
        return (request, response, authentication) -> {
            response.setStatus(HttpServletResponse.SC_OK);
            response.setContentType(MediaType.APPLICATION_JSON_VALUE);
            SamlAuthenticatedPrincipal principal = (SamlAuthenticatedPrincipal) authentication.getPrincipal();
            response.getWriter().write("{\"authenticated\":true,\"name\":\"" + escape(principal.getName()) + "\"}");
        };
    }

    @Override
    public Authentication attemptAuthentication(HttpServletRequest request, HttpServletResponse response) {
        String samlResponse = request.getParameter("SAMLResponse");
        if (!StringUtils.hasText(samlResponse)) {
            throw new BadCredentialsException("Missing SAMLResponse");
        }
        return getAuthenticationManager().authenticate(new SamlAuthenticationToken(samlResponse));
    }

    @Override
    protected boolean requiresAuthentication(HttpServletRequest request, HttpServletResponse response) {
        return "/saml/acs".equals(request.getRequestURI()) && "POST".equalsIgnoreCase(request.getMethod());
    }

    @Override
    protected void successfulAuthentication(HttpServletRequest request, HttpServletResponse response, FilterChain chain, Authentication authResult) throws IOException, ServletException {
        getSuccessHandler().onAuthenticationSuccess(request, response, authResult);
    }

    private String escape(String input) {
        return input.replace("\\", "\\\\").replace("\"", "\\\"");
    }
}

