class SamlService {

    private final SamlProperties properties;
    private final Clock clock = Clock.systemUTC();

    SamlService(SamlProperties properties) {
        this.properties = properties;
    }

    public SamlAuthenticatedPrincipal validateAndExtractPrincipal(String base64Response) {
        Response response = parseResponse(base64Response);

        if (!StatusCode.SUCCESS.equals(response.getStatus().getStatusCode().getValue())) {
            throw new BadCredentialsException("SAML response is not successful");
        }

        boolean responseSignatureValid = response.isSigned() && validateSignature(response.getSignature());
        if (!responseSignatureValid && response.getAssertions().stream().noneMatch(a -> a.isSigned() && validateSignature(a.getSignature()))) {
            throw new BadCredentialsException("No valid signature found on response or assertions");
        }

        Assertion assertion = response.getAssertions().stream().findFirst()
            .orElseThrow(() -> new BadCredentialsException("No assertion found"));

        validateConditions(assertion.getConditions());

        String name = assertion.getSubject() != null && assertion.getSubject().getNameID() != null
            ? assertion.getSubject().getNameID().getValue()
            : null;

        if (!StringUtils.hasText(name)) {
            throw new BadCredentialsException("Missing subject NameID");
        }

        return new SamlAuthenticatedPrincipal(name);
    }

    private Response parseResponse(String base64Response) {
        try {
            byte[] decoded = Base64.getDecoder().decode(base64Response);
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            factory.setNamespaceAware(true);
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            Document document = factory.newDocumentBuilder().parse(new ByteArrayInputStream(decoded));
            Element element = document.getDocumentElement();
            UnmarshallerFactory unmarshallerFactory = XMLObjectProviderRegistrySupport.getUnmarshallerFactory();
            Unmarshaller unmarshaller = unmarshallerFactory.getUnmarshaller(element);
            XMLObject xmlObject = unmarshaller.unmarshall(element);
            return (Response) xmlObject;
        } catch (Exception e) {
            throw new BadCredentialsException("Invalid SAML response", e);
        }
    }

    private boolean validateSignature(Signature signature) {
        try {
            X509Certificate certificate = parseCertificate(properties.getIdpCertificatePem());
            BasicX509Credential credential = new BasicX509Credential(certificate);
            SignatureValidator.validate(signature, credential);
            return true;
        } catch (SignatureException e) {
            return false;
        } catch (Exception e) {
            throw new BadCredentialsException("Signature validation failure", e);
        }
    }

    private void validateConditions(Conditions conditions) {
        if (conditions == null) {
            throw new BadCredentialsException("Missing assertion conditions");
        }
        Instant now = Instant.now(clock);
        if (conditions.getNotBefore() != null && now.isBefore(conditions.getNotBefore())) {
            throw new BadCredentialsException("Assertion not yet valid");
        }
        if (conditions.getNotOnOrAfter() != null && !now.isBefore(conditions.getNotOnOrAfter())) {
            throw new BadCredentialsException("Assertion expired");
        }
    }

    private X509Certificate parseCertificate(String pem) throws Exception {
        String normalized = pem
            .replace("-----BEGIN CERTIFICATE-----", "")
            .replace("-----END CERTIFICATE-----", "")
            .replaceAll("\\s+", "");
        byte[] der = Base64.getDecoder().decode(normalized);
        CertificateFactory cf = CertificateFactory.getInstance("X.509");
        return (X509Certificate) cf.generateCertificate(new ByteArrayInputStream(der));
    }
}

