    public String me(Authentication authentication) {
        SamlAuthenticatedPrincipal principal = (SamlAuthenticatedPrincipal) authentication.getPrincipal();
        return "{\"name\":\"" + principal.getName().replace("\\", "\\\\").replace("\"", "\\\"") + "\"}";
    }

    private String buildRedirectUrl() throws Exception {
        AuthnRequest authnRequest = buildAuthnRequest();
        String xml = serialize(authnRequest);
        String encoded = deflateAndBase64Encode(xml);
        return properties.getIdpSsoUrl() + "?SAMLRequest=" + java.net.URLEncoder.encode(encoded, StandardCharsets.UTF_8);
    }

    private AuthnRequest buildAuthnRequest() {
        QName qName = AuthnRequest.DEFAULT_ELEMENT_NAME;
        AuthnRequest authnRequest = (AuthnRequest) XMLObjectProviderRegistrySupport.getBuilderFactory()
            .getBuilder(qName)
            .buildObject(qName);

        Issuer issuer = (Issuer) XMLObjectProviderRegistrySupport.getBuilderFactory()
            .getBuilder(Issuer.DEFAULT_ELEMENT_NAME)
            .buildObject(Issuer.DEFAULT_ELEMENT_NAME);
        issuer.setValue(properties.getSpEntityId());

        NameIDPolicy nameIDPolicy = (NameIDPolicy) XMLObjectProviderRegistrySupport.getBuilderFactory()
            .getBuilder(NameIDPolicy.DEFAULT_ELEMENT_NAME)
            .buildObject(NameIDPolicy.DEFAULT_ELEMENT_NAME);
        nameIDPolicy.setAllowCreate(true);

        authnRequest.setID("_" + UUID.randomUUID());
        authnRequest.setIssueInstant(Instant.now());
        authnRequest.setDestination(properties.getIdpSsoUrl());
        authnRequest.setProtocolBinding(SAMLConstants.SAML2_POST_BINDING_URI);
        authnRequest.setAssertionConsumerServiceURL(properties.getAcsUrl());
        authnRequest.setIssuer(issuer);
        authnRequest.setNameIDPolicy(nameIDPolicy);
        return authnRequest;
    }

    private String serialize(XMLObject xmlObject) throws Exception {
        Marshaller marshaller = XMLObjectProviderRegistrySupport.getMarshallerFactory().getMarshaller(xmlObject);
        Element element = marshaller.marshall(xmlObject);
        StringWriter writer = new StringWriter();
        javax.xml.transform.Transformer transformer = javax.xml.transform.TransformerFactory.newInstance().newTransformer();
        transformer.transform(new javax.xml.transform.dom.DOMSource(element), new javax.xml.transform.stream.StreamResult(writer));
        return writer.toString();
    }

    private String deflateAndBase64Encode(String input) throws IOException {
        java.io.ByteArrayOutputStream outputStream = new java.io.ByteArrayOutputStream();
        Deflater deflater = new Deflater(Deflater.DEFLATED, true);
        try (DeflaterOutputStream deflaterStream = new DeflaterOutputStream(outputStream, deflater)) {
            deflaterStream.write(input.getBytes(StandardCharsets.UTF_8));
        }
        return Base64.getEncoder().encodeToString(outputStream.toByteArray());
    }
